    var dy = e.clientY - dragState.startY;
    var tx = dragState.tx + dx;
    var ty = dragState.ty + dy;
    var baseTransform = dragState.baseTransform || '';
    dragState.el.style.transform = 'translate(' + tx + 'px,' + ty + 'px)' + (baseTransform ? ' ' + baseTransform : '');
