      Math.abs(((e && typeof e.clientX === 'number') ? e.clientX : dragState.startX) - dragState.startX) > 4 ||
      Math.abs(((e && typeof e.clientY === 'number') ? e.clientY : dragState.startY) - dragState.startY) > 4;

